    // MARK: - JavaScript Bridge Script
    
    private func createBridgeScript() -> String {
        return """
        (function() {
            // Create the native bridge interface
            window.NativeBridge = {
                _callbackCounter: 0,
                _callbacks: {},
                
                // Internal: send message to native
                _postMessage: function(action, data, callback) {
                    var callbackId = null;
                    if (callback) {
                        callbackId = 'cb_' + (++this._callbackCounter);
                        this._callbacks[callbackId] = callback;
                    }
                    window.webkit.messageHandlers.\(messageHandlerName).postMessage({
                        action: action,
                        data: data || {},
                        callbackId: callbackId
                    });
                },
                
                // Internal: receive callback from native
                _receiveCallback: function(callbackId, success, data) {
                    var callback = this._callbacks[callbackId];
                    if (callback) {
                        callback(success, data);
                        delete this._callbacks[callbackId];
                    }
                },
                
                // Camera APIs
                openCamera: function(options, callback) {
                    this._postMessage('openCamera', options, callback);
                },
                
                requestCameraPermission: function(callback) {
                    this._postMessage('requestCameraPermission', {}, callback);
                },
                
                // Push Notification APIs
                requestPushNotifications: function(callback) {
                    this._postMessage('requestPushNotifications', {}, callback);
                },
                
                getPushToken: function(callback) {
                    this._postMessage('getPushToken', {}, callback);
                },
                
                // In-App Purchase APIs
                initiateInAppPurchase: function(productId, callback) {
                    this._postMessage('initiateInAppPurchase', { productId: productId }, callback);
                },
                
                restorePurchases: function(callback) {
                    this._postMessage('restorePurchases', {}, callback);
                },
                
                // Device APIs
                getDeviceInfo: function(callback) {
                    this._postMessage('getDeviceInfo', {}, callback);
                },
                
                hapticFeedback: function(style) {
                    this._postMessage('hapticFeedback', { style: style || 'medium' });
                },
                
                shareContent: function(text, url, callback) {
                    this._postMessage('shareContent', { text: text, url: url }, callback);
                },
                
                setStatusBarStyle: function(style) {
                    this._postMessage('setStatusBarStyle', { style: style });
                },
                
                // Platform detection
                isNativeApp: true,
                platform: 'ios'
            };
            
            // Dispatch event to notify web app that bridge is ready
            var event = new CustomEvent('nativeBridgeReady', { detail: { platform: 'ios' } });
            document.dispatchEvent(event);
            
            console.log('[NativeBridge] iOS bridge initialized');
        })();
        """
    }
    
